# Cost normalization
def normalize_costs(cost_per_task: dict[str, float]) -> dict[str, float]:
    """
    cost_per_task: {model_id: cost_usd_per_task}
    Returns: {model_id: normalized_score} where cheapest = 1.0
    """
    min_cost = min(cost_per_task.values())
    return {model: min_cost / cost for model, cost in cost_per_task.items()}

# Example costs from harness run:
costs = {
    "claude-haiku-4-5-20251001": 0.0008,
    "claude-sonnet-5":           0.0031,
    "claude-opus-4-8":           0.0145,
}
normalized = normalize_costs(costs)
# {"claude-haiku-4-5": 1.000, "claude-sonnet-5": 0.258, "claude-opus-4-8": 0.055}
# Note: Opus scores 0.055 on cost — this heavily penalizes it in the weighted total
